    #[test]
    fn carried_sol_leg_budget_floor_moves_reentered_target_window_replay_beyond_replay_sol_leg_incomplete_stage1(
    ) -> Result<()> {
        let temp = tempdir().context("failed to create tempdir")?;
        let runtime_db_path = temp
            .path()
            .join("stage1-carried-sol-leg-budget-floor-a-b.db");
        let mut runtime_store = SqliteStore::open(Path::new(&runtime_db_path))?;
        let migration_dir = Path::new(env!("CARGO_MANIFEST_DIR")).join("../../migrations");
        runtime_store.run_migrations(&migration_dir)?;

        let now = DateTime::parse_from_rfc3339("2026-04-10T12:48:09Z")
            .expect("valid timestamp")
            .with_timezone(&Utc);
        let mut config = stage1_runtime_config();
        config.metric_snapshot_interval_seconds = 3_600;
        config.max_fetch_swaps_per_cycle = 100;
        config.max_fetch_pages_per_cycle = 5;
        config.fetch_time_budget_ms = 25_000;
        let discovery = DiscoveryService::new(config.clone(), permissive_shadow_quality());
        let current_metrics_window_start = metrics_window_start_for_test(&config, now);
        let stale_metrics_window_start = current_metrics_window_start
            - Duration::seconds(config.metric_snapshot_interval_seconds as i64);
        let (mut replay_state, _metrics_window_start) =
            seed_stage1_dense_partial_sol_leg_replay_checkpoint_fixture(
                &runtime_store,
                &discovery,
                &config,
                now,
                4_000,
                20,
            )?;
        replay_state.metrics_window_start = stale_metrics_window_start;
        replay_state.payload.replay_wallet_stats_milestone_reached = true;
        replay_state
            .payload
            .replay_candidate_activity_backfill_required = true;
        replay_state
            .payload
            .replay_sol_leg_last_partial_cycle_pages_processed = 20;
        replay_state
            .payload
            .replay_sol_leg_last_partial_cycle_rows_processed = 2_000;
        replay_state
            .payload
            .replay_sol_leg_last_partial_cycle_elapsed_ms = 100_000;

        let base_contract = PersistedStreamPriorityRecoveryContract {
            time_budget: StdDuration::from_secs(60),
            collect_buy_mints_phase_page_limit_override: Some(160),
            replay_wallet_stats_phase_page_limit_override: Some(92),
            replay_sol_leg_phase_page_limit_override: Some(300),
            reason: Some("runtime_window_complete_stale_publication_truth"),
        };

        let mut old_like = replay_state.clone();
        old_like.payload.replay_sol_leg_budget_floor_pages = 0;
        let old_like_contract = discovery
            .deepen_persisted_stream_priority_recovery_contract_for_state_at(
                &old_like,
                config.max_fetch_swaps_per_cycle,
                config.max_fetch_pages_per_cycle,
                base_contract,
                Some(now),
            );
        let old_like_advance = discovery
            .advance_persisted_stream_replay_optimized_with_wallet_stats_phase_page_limit(
                &runtime_store,
                &mut old_like,
                config.max_fetch_swaps_per_cycle,
                config.max_fetch_pages_per_cycle,
                old_like_contract.replay_wallet_stats_phase_page_limit_override,
                old_like_contract.replay_sol_leg_phase_page_limit_override,
                false,
                Instant::now() + StdDuration::from_secs(30),
            )?;
        assert!(!old_like_advance.source_exhausted);
        assert_eq!(
            DiscoveryService::persisted_stream_publishable_checkpoint_blocker_from_state(
                &old_like
            ),
            "replay_sol_leg_incomplete",
            "old behavior reproduces the exact remaining seam: the re-entered stale-target replay lane keeps advancing rows, but without a carried sol_leg budget floor it still remains on replay_sol_leg_incomplete"
        );

        let mut carried_floor = replay_state;
        carried_floor.payload.replay_sol_leg_budget_floor_pages = 80;
        let carried_floor_contract = discovery
            .deepen_persisted_stream_priority_recovery_contract_for_state_at(
                &carried_floor,
                config.max_fetch_swaps_per_cycle,
                config.max_fetch_pages_per_cycle,
                base_contract,
                Some(now),
            );
        let carried_floor_advance = discovery
            .advance_persisted_stream_replay_optimized_with_wallet_stats_phase_page_limit(
                &runtime_store,
                &mut carried_floor,
                config.max_fetch_swaps_per_cycle,
                config.max_fetch_pages_per_cycle,
                carried_floor_contract.replay_wallet_stats_phase_page_limit_override,
                carried_floor_contract.replay_sol_leg_phase_page_limit_override,
                false,
                Instant::now() + StdDuration::from_secs(30),
            )?;

        assert!(
            carried_floor_contract
                .replay_sol_leg_phase_page_limit_override
                .zip(old_like_contract.replay_sol_leg_phase_page_limit_override)
                .is_some_and(|(new_limit, old_limit)| new_limit > old_limit),
            "the carried sol_leg budget floor must widen the exact re-entered stale-target replay lane, not just preserve the same 60-page suffix-only contract"
        );
        assert!(
            carried_floor_advance.replay_sol_leg_pages_processed
                > old_like_advance.replay_sol_leg_pages_processed,
            "the carried-budget-floor contract must materially advance the exact same re-entered stale-target replay cursor farther than the old suffix-only lane"
        );
        assert_ne!(
            DiscoveryService::persisted_stream_publishable_checkpoint_blocker_from_state(
                &carried_floor
            ),
            "replay_sol_leg_incomplete",
            "with the carried sol_leg budget floor preserved across target rollover, the same re-entered replay checkpoint should move beyond replay_sol_leg_incomplete instead of learning the smaller suffix-only lane again"
        );
        assert!(
            carried_floor.payload.replay_candidate_activity_backfill_pending
                || carried_floor_advance.source_exhausted,
            "moving beyond the blocker must mean the wider carried-floor lane exhausted the remaining SOL-leg source and entered exact candidate-wallet backfill, not just that the checkpoint logged a different metric"
        );
        Ok(())
    }

    #[test]
    fn pinned_stale_post_wallet_stats_replay_target_beats_old_like_retargeted_sol_leg_restart_stage1(
    ) -> Result<()> {
        let temp = tempdir().context("failed to create tempdir")?;
        let runtime_db_path = temp
            .path()
            .join("stage1-pinned-vs-retargeted-stale-sol-leg-replay.db");
        let mut runtime_store = SqliteStore::open(Path::new(&runtime_db_path))?;
        let migration_dir = Path::new(env!("CARGO_MANIFEST_DIR")).join("../../migrations");
        runtime_store.run_migrations(&migration_dir)?;

        let now = DateTime::parse_from_rfc3339("2026-04-10T15:45:35Z")
            .expect("valid timestamp")
            .with_timezone(&Utc);
        let mut config = stage1_runtime_config();
        config.metric_snapshot_interval_seconds = 60;
        config.max_fetch_swaps_per_cycle = 100;
        config.max_fetch_pages_per_cycle = 5;
        config.fetch_time_budget_ms = 25_000;
        let discovery = DiscoveryService::new(config.clone(), permissive_shadow_quality());
        let target_one_now =
            now + Duration::seconds(config.metric_snapshot_interval_seconds as i64 + 61);
        let target_one_window_start =
            target_one_now - Duration::days(config.scoring_window_days.max(1) as i64);
        let target_one_metrics_window_start =
            metrics_window_start_for_test(&config, target_one_now);
        let target_two_now =
            target_one_now + Duration::seconds(config.metric_snapshot_interval_seconds as i64 + 61);
        let target_two_window_start =
            target_two_now - Duration::days(config.scoring_window_days.max(1) as i64);
        let target_two_metrics_window_start =
            metrics_window_start_for_test(&config, target_two_now);

        let (mut target_one_state, _source_metrics_window_start) =
            seed_stage1_dense_partial_sol_leg_replay_checkpoint_fixture(
                &runtime_store,
                &discovery,
                &config,
                now,
                8_000,
                20,
            )?;
        assert!(
            discovery.prepare_persisted_stream_rebuild_for_metrics_window_rollover(
                &mut target_one_state,
                target_one_window_start,
                target_one_metrics_window_start,
                target_one_now,
            )?
        );
        advance_carried_target_until_replay_or_upstream_block_for_test(
            &discovery,
            &runtime_store,
            &mut target_one_state,
            64,
            64,
            config.max_fetch_swaps_per_cycle,
            config.max_fetch_pages_per_cycle,
        )?;
        assert_eq!(
            target_one_state.phase,
            DiscoveryPersistedRebuildPhase::Replay
        );
        assert!(target_one_state.payload.replay_wallet_stats_complete);
        assert_eq!(
            DiscoveryService::persisted_stream_publishable_checkpoint_blocker_from_state(
                &target_one_state
            ),
            "replay_sol_leg_incomplete"
        );

        let advance_partial_sol_leg_once = |state: &mut PersistedStreamRebuildState,
                                            cycle_now: DateTime<Utc>|
         -> Result<PersistedStreamPhaseAdvance> {
            let contract = discovery
                .deepen_persisted_stream_priority_recovery_contract_for_state_at(
                    state,
                    config.max_fetch_swaps_per_cycle,
                    config.max_fetch_pages_per_cycle,
                    PersistedStreamPriorityRecoveryContract {
                        time_budget: StdDuration::from_secs(60),
                        collect_buy_mints_phase_page_limit_override: Some(160),
                        replay_wallet_stats_phase_page_limit_override: Some(92),
                        replay_sol_leg_phase_page_limit_override: Some(300),
                        reason: Some("runtime_window_complete_stale_publication_truth"),
                    },
                    Some(cycle_now),
                );
            let advance = discovery
                .advance_persisted_stream_replay_optimized_with_wallet_stats_phase_page_limit(
                    &runtime_store,
                    state,
                    config.max_fetch_swaps_per_cycle,
                    config.max_fetch_pages_per_cycle,
                    contract.replay_wallet_stats_phase_page_limit_override,
                    contract.replay_sol_leg_phase_page_limit_override,
                    false,
                    Instant::now() + StdDuration::from_secs(30),
                )?;
            state.replay_rows_processed = state
                .replay_rows_processed
                .saturating_add(advance.rows_processed);
            state.replay_pages_processed = state
                .replay_pages_processed
                .saturating_add(advance.pages_processed);
            state.phase_cursor = advance.phase_cursor.clone();
            DiscoveryService::persist_partial_replay_frontier_hints_after_cycle(
                state,
                config.max_fetch_swaps_per_cycle,
                true,
                ReplayWalletStatsDayCountSourceProgress::default(),
                advance.replay_sol_leg_elapsed_ms.max(1),
                advance.budget_exhausted_reason,
                contract.replay_sol_leg_phase_page_limit_override,
                advance.replay_sol_leg_pages_processed,
                advance.replay_sol_leg_rows_processed,
                advance.replay_sol_leg_elapsed_ms,
            );
            Ok(advance)
        };

        let target_one_advance =
            advance_partial_sol_leg_once(&mut target_one_state, target_one_now)?;
        assert!(
            !target_one_advance.source_exhausted,
            "the first carried target must still be mid-sol-leg so the second bucket can reproduce the moving-goalpost seam"
        );
        assert_eq!(
            DiscoveryService::persisted_stream_publishable_checkpoint_blocker_from_state(
                &target_one_state
            ),
            "replay_sol_leg_incomplete"
        );
        assert!(target_one_state.phase_cursor.is_some());
        assert!(target_one_state.replay_rows_processed > 0);
        let target_one_second_advance =
            advance_partial_sol_leg_once(&mut target_one_state, target_one_now)?;
        assert!(
            !target_one_second_advance.source_exhausted,
            "the first carried target must still remain mid-sol-leg after a second bounded cycle so the next bucket can reproduce the moving-goalpost reset against a materially advanced frozen cursor"
        );
        assert_eq!(
            DiscoveryService::persisted_stream_publishable_checkpoint_blocker_from_state(
                &target_one_state
            ),
            "replay_sol_leg_incomplete"
        );

        let mut old_like = target_one_state.clone();
        assert!(
            discovery.prepare_persisted_stream_rebuild_for_metrics_window_rollover(
                &mut old_like,
                target_two_window_start,
                target_two_metrics_window_start,
                target_two_now,
            )?,
            "old behavior must rebase the aged-out downstream replay target onto the newer moving window before the A/B can compare it to the pinned frozen target"
        );
        advance_carried_target_until_replay_or_upstream_block_for_test(
            &discovery,
            &runtime_store,
            &mut old_like,
            64,
            64,
            config.max_fetch_swaps_per_cycle,
            config.max_fetch_pages_per_cycle,
        )?;
        assert_eq!(old_like.phase, DiscoveryPersistedRebuildPhase::Replay);
        let _old_like_advance = advance_partial_sol_leg_once(&mut old_like, target_two_now)?;
        assert_eq!(
            old_like.metrics_window_start,
            target_two_metrics_window_start
        );
        assert_eq!(
            DiscoveryService::persisted_stream_publishable_checkpoint_blocker_from_state(
                &old_like
            ),
            "replay_sol_leg_incomplete",
            "old rollover behavior reproduces the exact moving-goalpost failure: once the target rebases, the replay checkpoint loses its frozen downstream cursor/accumulators and stays on replay_sol_leg_incomplete"
        );

        runtime_store.upsert_discovery_persisted_rebuild_state(
            &DiscoveryService::persisted_stream_rebuild_row(&target_one_state, target_one_now)?,
        )?;
        let (mut pinned, restore_outcome) = discovery
            .load_or_start_persisted_stream_rebuild_state(
                &runtime_store,
                target_two_window_start,
                target_two_metrics_window_start,
                target_two_now,
            )?;
        assert_eq!(
            restore_outcome,
            PersistedStreamRebuildRestoreOutcome::ResumedStaleMetricsWindow
        );
        assert_eq!(pinned.metrics_window_start, target_one_metrics_window_start);
        assert_eq!(pinned.phase_cursor, target_one_state.phase_cursor);
        let pinned_advance = advance_partial_sol_leg_once(&mut pinned, target_two_now)?;

        assert!(
            pinned.replay_rows_processed > old_like.replay_rows_processed,
            "keeping the frozen downstream target alive must preserve and extend the exact sol-leg replay prefix instead of resetting it onto the newer moving target"
        );
        assert_ne!(
            DiscoveryService::persisted_stream_publishable_checkpoint_blocker_from_state(&pinned),
            "replay_sol_leg_incomplete",
            "pinning the frozen post-wallet-stats target until its first exact checkpoint should move the same lineage beyond replay_sol_leg_incomplete instead of reopening the blocker on each bucket roll"
        );
        assert!(
            pinned.payload.replay_candidate_activity_backfill_pending || pinned_advance.source_exhausted,
            "moving beyond the blocker must mean the frozen target exhausted the remaining sol-leg source and entered exact candidate activity backfill, not merely that a different metric changed"
        );
        Ok(())
    }

    #[test]
    fn exact_target_filtered_sol_leg_replay_beats_broad_tail_on_pinned_lineage_stage1() -> Result<()>
    {
        let temp = tempdir().context("failed to create tempdir")?;
        let runtime_db_path = temp
            .path()
            .join("stage1-exact-target-filtered-sol-leg-replay.db");
        let mut runtime_store = SqliteStore::open(Path::new(&runtime_db_path))?;
        let migration_dir = Path::new(env!("CARGO_MANIFEST_DIR")).join("../../migrations");
        runtime_store.run_migrations(&migration_dir)?;

        let source_now = DateTime::parse_from_rfc3339("2026-04-07T17:38:43Z")
            .expect("valid timestamp")
            .with_timezone(&Utc);
        let mut config = live_restored_rug_policy_discovery_config_for_tests();
        config.require_open_positions_for_publication = true;
        config.observed_swaps_retention_days = 14;
        config.max_window_swaps_in_memory = 64;
        config.max_fetch_swaps_per_cycle = 100;
        config.max_fetch_pages_per_cycle = 5;
        config.fetch_time_budget_ms = 25_000;
        let discovery = DiscoveryService::new(config.clone(), permissive_shadow_quality());
        let (full_swaps, legit_wallet_ids, _junk_wallet_ids) =
            long_horizon_carry_vs_refill_drain_fixture_swaps(&config, source_now);
        insert_observed_swaps_and_seed_runtime_cursor(&runtime_store, &full_swaps)?;

        let helper_by_wallet = replay_streaming_wallet_accumulators_from_swaps_for_test(
            &discovery,
            &full_swaps,
            source_now,
        );
        let exact_target_buy_mints = discovery
            .discovery_critical_target_buy_mints_from_accumulators(
                &runtime_store,
                &helper_by_wallet,
                source_now,
            )?;
        assert!(
            !exact_target_buy_mints.is_empty(),
            "the reduced live-like lineage must first recover a non-empty exact target-mint surface before the remaining replay seam can be attributed to the broad non-target SOL-leg tail"
        );
        let exact_target_buy_mint_set: HashSet<String> =
            exact_target_buy_mints.iter().cloned().collect();
        let exact_target_only_swaps = omit_nonfollowed_market_context_swaps_except_tokens(
            &full_swaps,
            &exact_target_buy_mint_set,
        );
        assert!(
            exact_target_only_swaps.len() < full_swaps.len(),
            "the reduced live-like seam must actually leave a generic non-target SOL-leg tail behind for the old broad replay path to consume"
        );
        let last_exact_target_sol_leg = full_swaps
            .iter()
            .rev()
            .find(|swap| {
                sol_leg_token(swap).is_some_and(|token| exact_target_buy_mint_set.contains(token))
            })
            .cloned()
            .context("missing last exact-target SOL-leg swap in reduced live-like fixture")?;

        let window_start = source_now - Duration::days(config.scoring_window_days.max(1) as i64);
        let source_metrics_window_start = metrics_window_start_for_test(&config, source_now);
        let target_now =
            source_now + Duration::seconds(config.metric_snapshot_interval_seconds as i64 + 61);
        let target_window_start =
            target_now - Duration::days(config.scoring_window_days.max(1) as i64);
        let target_metrics_window_start = metrics_window_start_for_test(&config, target_now);
        let mut replay_state = discovery.start_persisted_stream_rebuild_state(
            window_start,
            source_metrics_window_start,
            source_now,
        );
        replay_state.phase = DiscoveryPersistedRebuildPhase::Replay;
        replay_state.horizon_end = source_now;
        replay_state.phase_cursor = Some(DiscoveryRuntimeCursor {
            ts_utc: last_exact_target_sol_leg.ts_utc,
            slot: last_exact_target_sol_leg.slot,
            signature: last_exact_target_sol_leg.signature.clone(),
        });
        replay_state.payload.collect_buy_mints_prepass_complete = true;
        replay_state.payload.collect_buy_mints_mode = CollectBuyMintsMode::FreshScan;
        replay_state.payload.unique_buy_mints =
            runtime_store.load_observed_buy_mints_in_window(window_start, source_now)?;
        replay_state.payload.buy_mint_counts = replay_state
            .payload
            .unique_buy_mints
            .iter()
            .cloned()
            .map(|mint| (mint, 1u32))
            .collect();
        replay_state.payload.token_quality_cache = fresh_token_quality_cache_for_mints_for_test(
            &replay_state.payload.unique_buy_mints,
            source_now,
        );
        replay_state.payload.token_quality_progress.next_mint_index =
            replay_state.payload.unique_buy_mints.len();
        replay_state.payload.replay_mode = ReplayMode::WalletStatsThenSolLeg;
        replay_state.payload.replay_wallet_stats_complete = true;
        replay_state.payload.replay_wallet_stats_milestone_reached = true;
        replay_state
            .payload
            .replay_candidate_activity_backfill_required = true;
        replay_state.payload.discovery_critical_target_buy_mints = exact_target_buy_mints.clone();
        replay_state.payload.by_wallet = replay_streaming_wallet_accumulators_from_swaps_for_test(
            &discovery,
            &exact_target_only_swaps,
            source_now,
        );
        replay_state.replay_rows_processed = exact_target_only_swaps.len();
        replay_state.replay_pages_processed = replay_state
            .replay_rows_processed
            .div_ceil(config.max_fetch_swaps_per_cycle.max(1));
        replay_state
            .payload
            .replay_sol_leg_last_partial_cycle_pages_processed = 306;
        replay_state
            .payload
            .replay_sol_leg_last_partial_cycle_rows_processed = 6_106_144;
        replay_state
            .payload
            .replay_sol_leg_last_partial_cycle_elapsed_ms = 2_511_710;
        replay_state.payload.replay_sol_leg_budget_floor_pages = 326;

        runtime_store.upsert_discovery_persisted_rebuild_state(
            &DiscoveryService::persisted_stream_rebuild_row(&replay_state, source_now)?,
        )?;
        let (resumed, restore_outcome) = discovery.load_or_start_persisted_stream_rebuild_state(
            &runtime_store,
            target_window_start,
            target_metrics_window_start,
            target_now,
        )?;
        assert_eq!(
            restore_outcome,
            PersistedStreamRebuildRestoreOutcome::ResumedStaleMetricsWindow,
            "the reduced live-like checkpoint must first resume on the pinned stale target so the remaining blocker is attributed to the exact post-c9c7f01 seam, not to pre-pin rollover rebasing"
        );
        let adjusted_contract = discovery
            .deepen_persisted_stream_priority_recovery_contract_for_state_at(
                &resumed,
                config.max_fetch_swaps_per_cycle,
                config.max_fetch_pages_per_cycle,
                PersistedStreamPriorityRecoveryContract {
                    time_budget: StdDuration::from_secs(60),
                    collect_buy_mints_phase_page_limit_override: Some(160),
                    replay_wallet_stats_phase_page_limit_override: Some(92),
                    replay_sol_leg_phase_page_limit_override: Some(300),
                    reason: Some("runtime_window_complete_stale_publication_truth"),
                },
                Some(target_now),
            );
        assert!(
            adjusted_contract
                .replay_sol_leg_phase_page_limit_override
                .is_some_and(|limit| limit > config.max_fetch_pages_per_cycle),
            "the reduced live-like seam must keep the already-landed deep sol-leg recovery contract active while the A/B isolates the remaining source-exhaustion boundary"
        );
        let broad_tail_row_count = adjusted_contract
            .replay_sol_leg_phase_page_limit_override
            .unwrap_or(config.max_fetch_pages_per_cycle)
            .saturating_mul(config.max_fetch_swaps_per_cycle.max(1))
            .saturating_add(config.max_fetch_swaps_per_cycle.max(1));
        let tail_base_ts = last_exact_target_sol_leg.ts_utc + Duration::seconds(1);
        for idx in 0..broad_tail_row_count {
            let ts = tail_base_ts + Duration::seconds((idx / 2) as i64);
            let token = format!("TokenStage1BroadTailNoise{idx:04}11111111111111111111");
            let (token_in, token_out, amount_in, amount_out) = if idx % 2 == 0 {
                (SOL_MINT.to_string(), token.clone(), 0.5, 50.0)
            } else {
                (token.clone(), SOL_MINT.to_string(), 50.0, 0.4)
            };
            let swap = SwapEvent {
                signature: format!("stage1-broad-tail-noise-{idx:04}"),
                wallet: format!("wallet_stage1_broad_tail_noise_{:04}", idx / 2),
                dex: "raydium".to_string(),
                token_in,
                token_out,
                amount_in,
                amount_out,
                slot: 9_000_000 + idx as u64,
                ts_utc: ts.min(source_now),
                exact_amounts: None,
            };
            runtime_store.insert_observed_swap(&swap)?;
        }
        let latest_tail_cursor = DiscoveryRuntimeCursor {
            ts_utc: (tail_base_ts
                + Duration::seconds((broad_tail_row_count.saturating_sub(1) / 2) as i64))
            .min(source_now),
            slot: 9_000_000 + broad_tail_row_count.saturating_sub(1) as u64,
            signature: format!(
                "stage1-broad-tail-noise-{:04}",
                broad_tail_row_count.saturating_sub(1)
            ),
        };
        runtime_store.upsert_discovery_runtime_cursor(&latest_tail_cursor)?;

        let mut old_like = resumed.clone();
        old_like.payload.discovery_critical_target_buy_mints.clear();
        let old_like_advance = discovery
            .advance_persisted_stream_replay_optimized_with_wallet_stats_phase_page_limit(
                &runtime_store,
                &mut old_like,
                config.max_fetch_swaps_per_cycle,
                config.max_fetch_pages_per_cycle,
                adjusted_contract.replay_wallet_stats_phase_page_limit_override,
                adjusted_contract.replay_sol_leg_phase_page_limit_override,
                false,
                Instant::now() + StdDuration::from_secs(30),
            )?;
        assert!(
            !old_like_advance.source_exhausted,
            "current broad replay semantics must still stay mid-sol-leg on the reduced live-like lineage because the remaining generic non-target tail keeps the source-exhaustion boundary moving"
        );
        assert_eq!(
            DiscoveryService::persisted_stream_publishable_checkpoint_blocker_from_state(
                &old_like
            ),
            "replay_sol_leg_incomplete",
            "without the persisted exact target-mint filter, the same pinned lineage should keep scanning the broad non-target SOL-leg tail and remain on the exact live blocker"
        );

        let mut filtered = resumed;
        let filtered_advance = discovery
            .advance_persisted_stream_replay_optimized_with_wallet_stats_phase_page_limit(
                &runtime_store,
                &mut filtered,
                config.max_fetch_swaps_per_cycle,
                config.max_fetch_pages_per_cycle,
                adjusted_contract.replay_wallet_stats_phase_page_limit_override,
                adjusted_contract.replay_sol_leg_phase_page_limit_override,
                false,
                Instant::now() + StdDuration::from_secs(30),
            )?;
        assert_ne!(
            DiscoveryService::persisted_stream_publishable_checkpoint_blocker_from_state(
                &filtered
            ),
            "replay_sol_leg_incomplete",
            "once the same pinned lineage replays only its persisted exact target-mint surface, the remaining broad non-target SOL-leg tail should stop blocking the handoff beyond replay_sol_leg_incomplete"
        );
        assert!(
            filtered.payload.replay_candidate_activity_backfill_pending
                || filtered_advance.source_exhausted
                || filtered.phase == DiscoveryPersistedRebuildPhase::PublishPending,
            "moving beyond the blocker must mean the exact-target-filtered replay exhausted the relevant SOL-leg source and entered candidate backfill or publish-pending, not merely that a different metric changed"
        );
        if filtered.phase == DiscoveryPersistedRebuildPhase::PublishPending {
            assert_eq!(
                filtered.payload.publish_pending_requested_wallet_ids,
                Some(legit_wallet_ids),
                "if the exact-target-filtered replay can finish candidate backfill in the same reduced live-like cycle, it must preserve the real non-empty publish set instead of fabricating a new one"
            );
        }
        Ok(())
    }

    #[test]
    fn run_cycle_runtime_window_complete_resumed_replay_wallet_stats_uses_deeper_priority_contract_stage1(
    ) -> Result<()> {
        let temp = tempdir().context("failed to create tempdir")?;
        let runtime_db_path = temp
            .path()
            .join("stage1-run-cycle-deep-replay-priority-contract.db");
        let mut runtime_store = SqliteStore::open(Path::new(&runtime_db_path))?;
        let migration_dir = Path::new(env!("CARGO_MANIFEST_DIR")).join("../../migrations");
        runtime_store.run_migrations(&migration_dir)?;

        let now = DateTime::parse_from_rfc3339("2026-04-02T14:41:24Z")
            .expect("valid timestamp")
            .with_timezone(&Utc);
        let mut config = stage1_runtime_config();
        config.metric_snapshot_interval_seconds = 3_600;
        config.max_fetch_swaps_per_cycle = 10_000;
        config.max_fetch_pages_per_cycle = 5;
        config.fetch_time_budget_ms = 15_000;
        let discovery = DiscoveryService::new(config.clone(), permissive_shadow_quality());
        let noise_wallets = 50_000usize;
        let (window_start, metrics_window_start) =
            seed_stage1_live_like_wallet_stats_backlog_fixture(
                &runtime_store,
                &config,
                now,
                noise_wallets,
                "stage1-run-cycle-deep-replay",
            )?;

        let mut replay_state =
            discovery.start_persisted_stream_rebuild_state(window_start, metrics_window_start, now);
        replay_state.phase = DiscoveryPersistedRebuildPhase::Replay;
        replay_state.horizon_end = now;
        replay_state.payload.replay_mode = ReplayMode::WalletStatsThenSolLeg;
        replay_state.payload.unique_buy_mints =
            runtime_store.load_observed_buy_mints_in_window(window_start, now)?;
        replay_state.payload.token_quality_progress.next_mint_index =
            replay_state.payload.unique_buy_mints.len();

        let partial = discovery.advance_persisted_stream_replay_wallet_stats(
            &runtime_store,
            &mut replay_state,
            config.max_fetch_swaps_per_cycle,
            8,
            Instant::now() + StdDuration::from_secs(30),
        )?;
        replay_state.payload.replay_wallet_stats_rows_processed = replay_state
            .payload
            .replay_wallet_stats_rows_processed
            .saturating_add(partial.replay_wallet_stats_rows_processed);
        replay_state.payload.replay_wallet_stats_pages_processed = replay_state
            .payload
            .replay_wallet_stats_pages_processed
            .saturating_add(partial.replay_wallet_stats_pages_processed);
        replay_state
            .payload
            .replay_wallet_stats_day_count_source_progress
            .merge(partial.replay_wallet_stats_day_count_source_progress);
        runtime_store.upsert_discovery_persisted_rebuild_state(
            &DiscoveryService::persisted_stream_rebuild_row(&replay_state, now)?,
        )?;
        runtime_store.set_discovery_publication_state(&DiscoveryPublicationStateUpdate {
            runtime_mode: DiscoveryRuntimeMode::FailClosed,
            reason: "raw_window_incomplete_no_recent_published_universe".to_string(),
            last_published_at: Some(
                now - discovery.runtime_published_universe_max_age() - Duration::seconds(1),
            ),
            last_published_window_start: Some(metrics_window_start - Duration::hours(1)),
            published_scoring_source: Some("raw_window".to_string()),
            published_wallet_ids: Some(Vec::new()),
        })?;

        let summary = discovery.run_cycle(&runtime_store, now)?;
        if runtime_store
            .load_discovery_persisted_rebuild_state()?
            .is_none()
        {
            assert_eq!(summary.runtime_mode, DiscoveryRuntimeMode::Healthy);
            let publication_state = runtime_store
                .discovery_publication_state()?
                .expect("publication state should exist after publish");
            assert!(
                publication_state
                    .published_wallet_ids
                    .as_ref()
                    .is_some_and(|wallets| !wallets.is_empty()),
                "if the deeper recovery contract completes the whole rebuild in one cycle, it must still publish a real non-empty wallet universe"
            );
            return Ok(());
        }

        let rebuild = load_persisted_stream_rebuild_state_for_test(&runtime_store)?;
        assert_eq!(rebuild.phase, DiscoveryPersistedRebuildPhase::Replay);
        assert!(
            rebuild.payload.replay_wallet_stats_complete,
            "the live run_cycle priority path should move the persisted checkpoint beyond wallet_stats instead of leaving it on the same incomplete subphase"
        );
        assert_eq!(rebuild.payload.replay_wallet_stats_wallet_cursor, None);
        Ok(())
    }

    #[test]
    fn run_cycle_runtime_window_complete_live_like_collect_buy_mints_uses_priority_recovery_contract_stage1(
    ) -> Result<()> {
        let temp = tempdir().context("failed to create tempdir")?;
        let baseline_db_path = temp
            .path()
            .join("stage1-runtime-priority-collect-buy-mints-baseline.db");
        let runtime_db_path = temp
            .path()
            .join("stage1-runtime-priority-collect-buy-mints-runtime.db");
        let migration_dir = Path::new(env!("CARGO_MANIFEST_DIR")).join("../../migrations");
        let mut baseline_store = SqliteStore::open(Path::new(&baseline_db_path))?;
        baseline_store.run_migrations(&migration_dir)?;
        let mut runtime_store = SqliteStore::open(Path::new(&runtime_db_path))?;
        runtime_store.run_migrations(&migration_dir)?;

        let now = DateTime::parse_from_rfc3339("2026-04-02T13:23:26Z")
            .expect("valid timestamp")
            .with_timezone(&Utc);
        let mut config = stage1_runtime_config();
        config.metric_snapshot_interval_seconds = 3_600;
        config.max_fetch_swaps_per_cycle = 20_000;
        config.max_fetch_pages_per_cycle = 5;
        config.fetch_time_budget_ms = 15_000;
        let discovery = DiscoveryService::new(config.clone(), permissive_shadow_quality());

        let baseline_window_start =
            seed_stage1_collect_buy_mints_noise_fixture(&baseline_store, &config, now, 6_000, 0)?;
        let metrics_window_start = metrics_window_start_for_test(&config, now);
        let PersistedStreamRebuildAdvanceOutcome::InProgress { telemetry } = discovery
            .advance_persisted_stream_rebuild(
                &baseline_store,
                baseline_window_start,
                metrics_window_start,
                now,
                config.max_fetch_swaps_per_cycle,
                config.max_fetch_pages_per_cycle,
                StdDuration::from_millis(config.fetch_time_budget_ms),
            )?
        else {
            panic!("baseline live-like collect_buy_mints rebuild should stay partial under the ordinary 15s contract");
        };
        assert_eq!(
            telemetry.phase,
            DiscoveryPersistedRebuildPhase::CollectBuyMints
        );
        assert!(
            telemetry.prepass_rows_processed
                <= COLLECT_BUY_MINTS_FRESH_SCAN_BATCH_CAP * config.max_fetch_pages_per_cycle,
            "baseline live contract should still stop near the old five-page fresh-scan ceiling before token quality starts"
        );
        assert!(
            telemetry.quality_next_mint_index <= telemetry.unique_buy_mints,
            "baseline direct rebuild may warm token-quality over the exact discovered mint prefix, but it must still remain in collect_buy_mints until the grouped source exhausts"
        );
        assert_eq!(telemetry.wallets_buffered, 0);

        let runtime_window_start =
            seed_stage1_collect_buy_mints_noise_fixture(&runtime_store, &config, now, 6_000, 0)?;
        runtime_store.set_discovery_publication_state(&DiscoveryPublicationStateUpdate {
            runtime_mode: DiscoveryRuntimeMode::FailClosed,
            reason: "raw_window_incomplete_no_recent_published_universe".to_string(),
            last_published_at: Some(
                now - discovery.runtime_published_universe_max_age() - Duration::seconds(1),
            ),
            last_published_window_start: Some(metrics_window_start - Duration::hours(1)),
            published_scoring_source: Some("raw_window".to_string()),
            published_wallet_ids: Some(Vec::new()),
        })?;

        let summary = discovery.run_cycle(&runtime_store, now)?;
        if runtime_store
            .load_discovery_persisted_rebuild_state()?
            .is_none()
        {
            assert_eq!(summary.scoring_source, "raw_window_persisted_stream");
            assert_eq!(summary.runtime_mode, DiscoveryRuntimeMode::Healthy);
            return Ok(());
        }

        let rebuild = load_persisted_stream_rebuild_state_for_test(&runtime_store)?;
        assert_eq!(rebuild.window_start, runtime_window_start);
        assert_eq!(rebuild.metrics_window_start, metrics_window_start);
        assert_ne!(
            rebuild.phase,
            DiscoveryPersistedRebuildPhase::CollectBuyMints,
            "run_cycle should reuse the widened fail-closed publication recovery contract instead of leaving the live-like rebuild stuck in fresh_scan after the old five-page prepass"
        );
        assert!(
            rebuild.prepass_rows_processed >= 6_000,
            "priority runtime recovery should drain the large live-like fresh-scan backlog before yielding back to the scheduler"
        );
        assert!(
            rebuild.payload.collect_buy_mints_cursor_token.is_none(),
            "once the widened runtime recovery contract drains fresh_scan, the persisted mint cursor should clear instead of preserving another partial collect_buy_mints prefix"
        );
        assert!(
            rebuild.payload.token_quality_progress.next_mint_index > 0
                || rebuild.payload.replay_wallet_stats_rows_processed > 0
                || rebuild.replay_rows_processed > 0,
            "after the widened runtime recovery contract drains fresh_scan, later token-quality or replay progress must already be visible"
        );
        Ok(())
    }

